const t2 = (() => {
  const source = { width: 3000, height: 1000 };
  const element = { left: 658, top: 0, width: 2256, height: 1692 };
  const crop = { top: 0, right: 0.53, bottom: 0.53, left: 0 };
  const coverScale = Math.max(element.width / source.width, element.height / source.height);
  const renderedObject = {
    width: source.width * coverScale,
    height: source.height * coverScale,
  };
  const objectOffset = {
    x: (element.width - renderedObject.width) / 2,
    y: (element.height - renderedObject.height) / 2,
  };
  const visibleBox = {
    x: element.left + element.width * crop.left,
    y: element.top + element.height * crop.top,
    width: element.width * (1 - crop.left - crop.right),
    height: element.height * (1 - crop.top - crop.bottom),
  };
  const sourceWindow = {
    x0: (0 - objectOffset.x) / coverScale,
    y0: (0 - objectOffset.y) / coverScale,
    x1: (visibleBox.width - objectOffset.x) / coverScale,
    y1: (visibleBox.height - objectOffset.y) / coverScale,
