      top: 0,
      width: round(1920 * scale),
      height: round(1080 * scale),
    },
    scaledVisibleBounds: {
      left: round((56 + visibleBox.x) * scale),
      top: round(visibleBox.y * scale),
      width: round(visibleBox.width * scale),
      height: round(visibleBox.height * scale),
    },
    sourceWindowInvariant: {
      x0: round(sourceWindow.x0),
      y0: round(sourceWindow.y0),
      x1: round(sourceWindow.x1),
      y1: round(sourceWindow.y1),
    },
  }));
  return {
