      current_pipeline_reference: 'src/tools/video-editor/compositions/VisualClip.tsx',
    },
    object_cover_math: {
      element_box: element,
      source_intrinsic_size: source,
      cover_scale: round(coverScale),
      rendered_object_size_inside_element: {
        width: round(renderedObject.width),
        height: round(renderedObject.height),
      },
      object_offset_inside_element: {
        x: round(objectOffset.x),
        y: round(objectOffset.y),
      },
      clip_path_box_within_element: {
        leftInsetPct: crop.left * 100,
        rightInsetPct: crop.right * 100,
        topInsetPct: crop.top * 100,
        bottomInsetPct: crop.bottom * 100,
      },
      visible_box_in_composition_space: Object.fromEntries(Object.entries(visibleBox).map(([k, v]) => [k, round(v)])),
      visible_source_window_after_object_cover_and_clip_path: {
        x0: round(sourceWindow.x0),
        y0: round(sourceWindow.y0),
        x1: round(sourceWindow.x1),
        y1: round(sourceWindow.y1),
      },
      interpretation: 'The visible crop shows source pixels roughly 833..1460 on the X axis, which is a centered mid-left slice of the 3000px-wide source. That comes from object-fit: cover centering within the full 2256x1692 element before clip-path applies.',
    },
    scale_comparison: scales,
    conclusion: {
      remotion_specific: false,
      transform_specific: false,
      summary: 'CSS transform scaling does not change which source pixels are visible. The same source window is produced at scale 1, 0.4, and 0.25. This rules out a Remotion-specific or browser canvas-size limit explanation for the reproduction and points to CSS semantics: object-fit: cover + clip-path percentages on an oversized positioned element.',
    },
    browser_attempt: {
      note: 'The standalone HTML reproduction was built successfully, but sandboxed headless browser execution returned no DOM/screenshot output. The comparison above is derived from standard CSS object-fit/clip-path geometry, which is deterministic for this case.',
    },
  };
})();

fs.writeFileSync(path.join(outDir, 't1-player-scaling-analysis.json'), JSON.stringify(t1, null, 2));
fs.writeFileSync(path.join(outDir, 't2-object-cover-analysis.json'), JSON.stringify(t2, null, 2));
