                  >
                    <span
                      className={`pointer-events-none absolute rounded-full transition ${lineClassName} ${isSelected ? 'bg-sky-300/70' : 'bg-white/0 group-hover:bg-white/50'}`}
                    />
                  </span>
                ))}
              </button>
            )}
          </div>
        );
